use bitwise::flow_frame::{self, FlowFrame, FIN};
use distributed_inference::model::NativeLlamaPipeline;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::io::{self, Read, Write};
use std::net::UdpSocket;
use std::time::SystemTime;

#[derive(Deserialize, Debug)]
enum Command {
    Load {
        path: String,
        draft_mode: bool,
        resonance_threshold: f64,
    },
    Generate {
        tokens: Vec<u32>,
        max_new_tokens: u32,
    },
    Verify {
        tokens: Vec<u32>,
        candidates: Vec<u32>,
    },
    Sync {
        tokens: Vec<u32>,
    },
}

#[derive(Serialize, Debug)]
enum Response {
    Loaded,
    Done { tokens: Vec<u32> },
    Error { message: String },
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    let mut udp_bind = None;
    for i in 1..args.len() {
        if args[i] == "--udp" && i + 1 < args.len() {
            udp_bind = Some(args[i + 1].clone());
        }
    }

    let mut pipeline: Option<NativeLlamaPipeline> = None;

    if let Some(addr) = udp_bind {
        run_udp(&addr, &mut pipeline);
    } else {
        run_ipc(&mut pipeline);
    }
}

fn handle_command(payload: &[u8], pipeline: &mut Option<NativeLlamaPipeline>) -> Option<Vec<u8>> {
    let resp = match bincode::deserialize::<Command>(payload) {
        Ok(Command::Load {
            path,
            draft_mode,
            resonance_threshold,
        }) => {
            eprintln!("[RUST] Process receiving Load: path={}", path);
            *pipeline = Some(NativeLlamaPipeline::new(
                path,
                draft_mode,
                resonance_threshold,
            ));
            Response::Loaded
        }
        Ok(Command::Generate {
            tokens,
            max_new_tokens,
        }) => {
            eprintln!(
                "[RUST] Process receiving Generate: n_prompt={}, max_new={}",
                tokens.len(),
                max_new_tokens
            );
            if let Some(ref mut p) = pipeline {
                match p.inner_generate(&tokens, max_new_tokens) {
                    Ok(res) => Response::Done { tokens: res },
                    Err(e) => Response::Error { message: e },
                }
            } else {
                Response::Error {
                    message: "Model not loaded".to_string(),
                }
            }
        }
        Ok(Command::Verify { tokens, candidates }) => {
            if let Some(ref mut p) = pipeline {
                eprintln!(
                    "[RUST] Running verify_batch for {} candidates",
                    candidates.len()
                );
                match p.inner_verify_batch(None, tokens, candidates) {
                    Ok(res) => {
                        eprintln!("[RUST] verify_batch accepted {} tokens", res.len());
                        Response::Done { tokens: res }
                    }
                    Err(e) => {
                        eprintln!("[RUST] verify_batch error: {}", e);
                        Response::Error {
                            message: e.to_string(),
                        }
                    }
                }
            } else {
                Response::Error {
                    message: "Model not loaded".to_string(),
                }
            }
        }
        Ok(Command::Sync { tokens }) => {
            if let Some(ref mut p) = pipeline {
                let current_pos = p.get_pos() as usize;
                if tokens.len() <= current_pos {
                    Response::Loaded
                } else {
                    let delta = &tokens[current_pos..];
                    p.inner_generate(delta, 0).unwrap();
                    Response::Loaded
                }
            } else {
                Response::Error {
                    message: "Model not loaded".to_string(),
                }
            }
        }
        Err(e) => {
            eprintln!("[RUST] Deserialization error: {}", e);
            Response::Error {
                message: format!("Invalid command: {}", e),
            }
        }
    };

    bincode::serialize(&resp).ok()
}

fn run_ipc(pipeline: &mut Option<NativeLlamaPipeline>) {
    let mut stdin = io::stdin().lock();
    let mut stdout = io::stdout().lock();
    let mut buf = Vec::new();
    let mut chunk = [0u8; 4096];

    loop {
        while let Some((frame, consumed)) = flow_frame::decode(&buf) {
            if let Some(payload) = handle_command(&frame.payload, pipeline) {
                let out_frame = FlowFrame {
                    stream_id: frame.stream_id,
                    sequence: frame.sequence,
                    flags: FIN,
                    payload,
                };
                let _ = stdout.write_all(&flow_frame::encode(&out_frame));
                let _ = stdout.flush();
            }
            buf.drain(..consumed);
        }

        match stdin.read(&mut chunk) {
            Ok(0) => break,
            Ok(n) => buf.extend_from_slice(&chunk[..n]),
            Err(_) => break,
        }
    }
}

const UDP_MTU: usize = 1472;
const FRAG_HEADER_SIZE: usize = 4;
const MAX_FRAG_PAYLOAD: usize = UDP_MTU - FRAG_HEADER_SIZE;

struct FragmentGroup {
    total: u8,
    received: HashMap<u8, Vec<u8>>,
    created_at: SystemTime,
}

fn run_udp(addr: &str, pipeline: &mut Option<NativeLlamaPipeline>) {
    let socket = UdpSocket::bind(addr).expect("Failed to bind UDP socket");
    eprintln!("[RUST] Swarm node listening on UDP {}", addr);

    let mut buf = [0u8; 65536];
    let mut fragments: HashMap<u16, FragmentGroup> = HashMap::new();

    loop {
        let (len, src) = match socket.recv_from(&mut buf) {
            Ok(res) => res,
            Err(_) => continue,
        };

        if len < FRAG_HEADER_SIZE {
            continue;
        }

        let frame_id = u16::from_be_bytes([buf[0], buf[1]]);
        let frag_index = buf[2];
        let frag_total = buf[3];
        let payload = &buf[FRAG_HEADER_SIZE..len];

        let reassembled = if frag_total == 1 {
            Some(payload.to_vec())
        } else {
            let entry = fragments.entry(frame_id).or_insert_with(|| FragmentGroup {
                total: frag_total,
                received: HashMap::new(),
                created_at: SystemTime::now(),
            });
            entry.received.insert(frag_index, payload.to_vec());

            if entry.received.len() == entry.total as usize {
                let mut full = Vec::new();
                for i in 0..frag_total {
                    if let Some(part) = entry.received.get(&i) {
                        full.extend_from_slice(part);
                    }
                }
                fragments.remove(&frame_id);
                Some(full)
            } else {
                None
            }
        };

        if let Some(full_frame_bytes) = reassembled {
            if let Some((frame, _)) = flow_frame::decode(&full_frame_bytes) {
                if let Some(resp_payload) = handle_command(&frame.payload, pipeline) {
                    let out_frame = FlowFrame {
                        stream_id: frame.stream_id,
                        sequence: frame.sequence,
                        flags: FIN,
                        payload: resp_payload,
                    };
                    let encoded = flow_frame::encode(&out_frame);

                    if encoded.len() <= MAX_FRAG_PAYLOAD {
                        let mut dg = vec![0u8; FRAG_HEADER_SIZE + encoded.len()];
                        dg[0..2].copy_from_slice(&frame_id.to_be_bytes());
                        dg[2] = 0;
                        dg[3] = 1;
                        dg[FRAG_HEADER_SIZE..].copy_from_slice(&encoded);
                        let _ = socket.send_to(&dg, src);
                    } else {
                        let total_frags = encoded.len().div_ceil(MAX_FRAG_PAYLOAD);
                        if total_frags > 255 {
                            eprintln!("[RUST] Response too large for UDP fragmentation!");
                            continue;
                        }
                        for i in 0..total_frags {
                            let start = i * MAX_FRAG_PAYLOAD;
                            let end = std::cmp::min(start + MAX_FRAG_PAYLOAD, encoded.len());
                            let chunk = &encoded[start..end];

                            let mut dg = vec![0u8; FRAG_HEADER_SIZE + chunk.len()];
                            dg[0..2].copy_from_slice(&frame_id.to_be_bytes());
                            dg[2] = i as u8;
                            dg[3] = total_frags as u8;
                            dg[FRAG_HEADER_SIZE..].copy_from_slice(chunk);
                            let _ = socket.send_to(&dg, src);
                        }
                    }
                }
            }
        }

        // Cleanup stale fragments
        if fragments.len() > 100 {
            let now = SystemTime::now();
            fragments.retain(|_, v| {
                if let Ok(elapsed) = now.duration_since(v.created_at) {
                    elapsed.as_secs() < 5
                } else {
                    true
                }
            });
        }
    }
}
